const publicOrigin = req => { const forwarded=String(req.headers['x-forwarded-host']||req.headers.host||'chirpsandroar.com').split(',')[0].trim(),fallback=/^(localhost|127\.0\.0\.1|\[::1\])/.test(forwarded)?'http':'https',proto=String(req.headers['x-forwarded-proto']||fallback).split(',')[0].trim();return `${proto==='http'?'http':'https'}://${forwarded.replace(/[^a-zA-Z0-9.:[\]-]/g,'')}`; };
const editDistance = (a,b) => { const row=Array.from({length:b.length+1},(_,i)=>i);for(let i=1;i<=a.length;i++){let diagonal=row[0];row[0]=i;for(let j=1;j<=b.length;j++){const above=row[j],cost=a[i-1]===b[j-1]?0:1;row[j]=Math.min(row[j]+1,row[j-1]+1,diagonal+cost);diagonal=above;}}return row[b.length]; };
const tokenMatch = (token,text) => { const words=normalizeSearch(text).split(' ').filter(Boolean);return words.some(word=>(token.length>=2&&word.includes(token))||(word.length>=3&&token.includes(word))||(token.length>=4&&word.length>=4&&editDistance(token,word)<=1)); };
