async function searchableGuides(query='',expertise='') {
  const rows=await db.prepare("SELECT * FROM guide_profiles WHERE verification_status='approved'").all(),events=await db.prepare("SELECT * FROM guide_events WHERE status='published' ORDER BY start_date,title").all(),variants=queryVariants(query),phrase=normalizeSearch(query),rawTokens=phrase.split(' ').filter(Boolean),wanted=normalizeSearch(expertise);
  return rows.map(row=>{const guide=guideDto(row),guideEvents=events.filter(event=>event.guide_id===guide.id).map(event=>({id:event.id,title:event.title,location:event.location,category:event.category,description:event.description,startDate:event.start_date,endDate:event.end_date}));const fields=[['guide name',guide.name,120],['location',[guide.location,...guide.workLocations].join(' '),80],['expertise',guide.expertise.join(' '),70],['event',guideEvents.map(event=>`${event.title} ${event.location} ${event.category}`).join(' '),95],['profile',guide.bio,25]],matched=new Set();let score=0,allMatch=true;for(const alternatives of variants){let best=0,bestLabel='';for(const [label,text,weight] of fields){if(alternatives.some(token=>tokenMatch(token,text))&&weight>best){best=weight;bestLabel=label;}}if(!best){allMatch=false;break;}score+=best;matched.add(bestLabel);}if(phrase){if(normalizeSearch(guide.name)===phrase)score+=300;else if(normalizeSearch(guide.name).startsWith(phrase))score+=180;if(guideEvents.some(event=>normalizeSearch(event.title)===phrase))score+=240;else if(guideEvents.some(event=>normalizeSearch(event.title).includes(phrase)))score+=130;if(normalizeSearch(guide.location).includes(phrase))score+=120;}const matchingEvents=guideEvents.filter(event=>!rawTokens.length||rawTokens.every(token=>tokenMatch(token,`${event.title} ${event.location} ${event.category} ${event.description}`)));return{...guide,events:guideEvents,matchingEvents,matchedOn:[...matched],searchScore:score,_matches:allMatch&&(!wanted||guide.expertise.some(item=>normalizeSearch(item).includes(wanted)))};}).filter(guide=>guide._matches).sort((a,b)=>b.searchScore-a.searchScore||b.rating-a.rating||b.reviewCount-a.reviewCount).map(({_matches,...guide})=>guide);
}

