async function createInvitation({kind,inviterUserId,guideId=null,name='',email='',phone='',message='',hours=168}) {
  const token=randomBytes(24).toString('base64url'),expiresAt=new Date(Date.now()+hours*3_600_000).toISOString(),result=await db.prepare(`INSERT INTO invitations(kind,token_hash,inviter_user_id,guide_id,recipient_name,recipient_email,recipient_phone,message,expires_at) VALUES(?,?,?,?,?,?,?,?,?)`).run(kind,sha256(token),inviterUserId,guideId,cleanText(name,100),cleanText(email,180).toLowerCase(),cleanText(phone,30),cleanText(message,800),expiresAt);
  return { id:Number(result.lastInsertRowid),token,url:`/invite.html?token=${token}`,expiresInHours:hours };
}
