route('GET', /^\/api\/invitations\/([A-Za-z0-9_-]+)$/, async (req,res,_url,match) => { const tokenHash=sha256(match[1]);let invite=await db.prepare("SELECT i.*,g.display_name guide_name,g.primary_location,g.profile_photo,(SELECT a.status FROM guide_applications a WHERE lower(a.email)=lower(i.recipient_email) ORDER BY a.created_at DESC LIMIT 1) application_status FROM invitations i LEFT JOIN guide_profiles g ON g.id=i.guide_id WHERE i.token_hash=?").get(tokenHash);if(!invite)return fail(res,404,'Invitation not found');if(new Date(`${invite.expires_at}Z`)<=new Date()&&['sent','opened'].includes(invite.status)){await db.prepare("UPDATE invitations SET status='expired' WHERE id=?").run(invite.id);invite.status='expired';}else if(invite.status==='sent'){await db.prepare("UPDATE invitations SET status='opened' WHERE id=?").run(invite.id);invite.status='opened';}reply(res,200,{invitation:{id:invite.id,kind:invite.kind,name:invite.recipient_name,email:invite.recipient_email,phone:invite.recipient_phone,message:invite.message,status:invite.status,expiresAt:invite.expires_at,applicationStatus:invite.application_status,guideId:invite.guide_id,guideName:invite.guide_name,guideLocation:invite.primary_location,guidePhoto:invite.profile_photo}}); });
