route('POST', /^\/api\/guide-onboarding\/([A-Za-z0-9_-]+)\/activate$/, async (req,res,_url,match) => { const invite=await db.prepare("SELECT * FROM invitations WHERE token_hash=? AND kind='guide_onboarding' AND status='accepted'").get(sha256(match[1]));if(!invite)return fail(res,410,'Onboarding invitation is not ready for activation');const application=await db.prepare("SELECT * FROM guide_applications WHERE lower(email)=lower(?) AND status='approved' ORDER BY created_at DESC LIMIT 1").get(invite.recipient_email);if(!application)return fail(res,409,'Your guide application must be approved before activation');const data=await body(req),password=String(data.password||'');if(password.length<8)return fail(res,400,'Use at least 8 characters for your password');const user=await db.prepare("SELECT * FROM users WHERE lower(email)=lower(?) AND role='guide'").get(invite.recipient_email);if(!user)return fail(res,404,'Approved guide account not found');await db.prepare("UPDATE users SET password_hash=?,updated_at=datetime('now') WHERE id=?").run(hashPassword(password),user.id);await createSession(res,user.id);reply(res,200,{user:publicUser(user),redirect:'/guide-admin.html'}); });

const promotionUrl=(req,code)=>{const proto=String(req.headers['x-forwarded-proto']||'http').split(',')[0],host=req.headers['x-forwarded-host']||req.headers.host||'127.0.0.1:3000';return `${proto}://${host}/index.html?promo=${encodeURIComponent(code)}`;};
route('GET', /^\/api\/promotions\/([A-Za-z0-9_-]+)$/, async (req,res,_url,match) => { const promotion=await db.prepare("SELECT p.*,g.display_name guide_name,g.primary_location,g.profile_photo,e.title event_title,e.start_date event_start_date FROM promotion_links p JOIN guide_profiles g ON g.id=p.guide_id LEFT JOIN guide_events e ON e.id=p.event_id WHERE p.code=? AND p.status='active'").get(match[1]);if(!promotion)return fail(res,404,'Promotion link is invalid or paused');await db.prepare('INSERT INTO promotion_clicks(promotion_link_id,referrer,user_agent) VALUES(?,?,?)').run(promotion.id,cleanText(req.headers.referer,500),cleanText(req.headers['user-agent'],500));await db.prepare('UPDATE promotion_links SET click_count=click_count+1 WHERE id=?').run(promotion.id);reply(res,200,{promotion:{code:promotion.code,campaignName:promotion.campaign_name,guideId:promotion.guide_id,guideName:promotion.guide_name,guideLocation:promotion.primary_location,guidePhoto:promotion.profile_photo,eventId:promotion.event_id,eventTitle:promotion.event_title,eventStartDate:promotion.event_start_date}}); });
