function requestedDates(start,end){const dates=[];for(let d=new Date(`${start}T00:00:00Z`),last=new Date(`${end}T00:00:00Z`);d<=last;d.setUTCDate(d.getUTCDate()+1))dates.push(d.toISOString().slice(0,10));return dates;}
async function notify(userId,type,title,message,targetUrl){await db.prepare('INSERT INTO notifications(user_id,type,title,body,target_url) VALUES(?,?,?,?,?)').run(userId,type,title,cleanText(message,300),targetUrl);}
route('POST', /^\/api\/booking-requests$/, async (req,res) => { const traveler=await requireUser(req,res,['traveler']);if(!traveler)return;const data=await body(req),guideId=Number(data.guideId),start=String(data.startDate||''),end=String(data.endDate||''),party=Number(data.travelers),slotLabel=cleanText(data.slotLabel||'Full day',60);if(!/^\d{4}-\d{2}-\d{2}$/.test(start)||!/^\d{4}-\d{2}-\d{2}$/.test(end)||start>end||party<1||party>12)return fail(res,400,'Valid dates and traveler count are required');const guide=await db.prepare("SELECT * FROM guide_profiles WHERE id=? AND verification_status='approved'").get(guideId);if(!guide)return fail(res,404,'Guide not found');const dates=requestedDates(start,end);if(dates.length>31)return fail(res,400,'Requests cannot exceed 31 days');const slots=await db.prepare("SELECT date,start_time,end_time,capacity-booked_count remaining FROM availability_slots WHERE guide_id=? AND label=? AND status='open' AND visibility='public' AND date BETWEEN ? AND ?").all(guideId,slotLabel,start,end),available=new Set(slots.filter(slot=>slot.remaining>=party).map(slot=>slot.date));if(dates.some(date=>!available.has(date)))return fail(res,409,`${slotLabel} does not have ${party} places available for every selected date`);let invitationId=null;if(data.invitationToken){const invite=await db.prepare("SELECT * FROM invitations WHERE token_hash=? AND guide_id=? AND kind='client_booking' AND status IN ('sent','opened','accepted') AND expires_at>datetime('now')").get(sha256(String(data.invitationToken)),guideId);if(invite){invitationId=invite.id;await db.prepare("UPDATE invitations SET status='accepted',accepted_user_id=?,accepted_at=coalesce(accepted_at,datetime('now')) WHERE id=?").run(traveler.id,invite.id);}}const promotion=data.promotionCode?await db.prepare("SELECT id FROM promotion_links WHERE code=? AND guide_id=? AND status='active'").get(String(data.promotionCode),guideId):null,message=cleanText(data.message,1000),estimate=guide.daily_rate*dates.length,slot=slots[0],result=await db.prepare(`INSERT INTO booking_requests(traveler_id,guide_id,invitation_id,start_date,end_date,travelers,focus,message,estimated_amount,response_deadline,slot_label,slot_start_time,slot_end_time,promotion_link_id) VALUES(?,?,?,?,?,?,?,?,?,datetime('now','+24 hours'),?,?,?,?)`).run(traveler.id,guideId,invitationId,start,end,party,cleanText(data.focus,100),message,estimate,slotLabel,slot?.start_time||null,slot?.end_time||null,promotion?.id||null),id=Number(result.lastInsertRowid),reference=`REQ-${String(id).padStart(6,'0')}`;await db.prepare('UPDATE booking_requests SET reference=? WHERE id=?').run(reference,id);if(promotion)await db.prepare('UPDATE promotion_links SET booking_count=booking_count+1 WHERE id=?').run(promotion.id);if(message)await db.prepare('INSERT INTO booking_messages(booking_request_id,sender_user_id,body) VALUES(?,?,?)').run(id,traveler.id,message);if(guide.user_id)await notify(guide.user_id,'booking_request','New booking request',`${traveler.name} requested ${party} places in ${slotLabel}, ${start} to ${end}.`,'/guide-admin.html#enquiries');reply(res,201,{request:{id,reference,guideId,startDate:start,endDate:end,travelers:party,focus:cleanText(data.focus,100),slotLabel,slotStartTime:slot?.start_time,slotEndTime:slot?.end_time,promotionAttributed:Boolean(promotion),estimatedAmount:estimate,paymentArrangement:'direct_with_guide',status:'pending',responseDeadline:'24 hours'}}); });
