const quoteDto=row=>row&&({id:row.id,bookingRequestId:row.booking_request_id,version:row.version,title:row.title,meetingLocation:row.meeting_location,meetingTime:row.meeting_time,itinerary:json(row.itinerary_json),inclusions:json(row.inclusions_json),exclusions:json(row.exclusions_json),guideNotes:row.guide_notes,currency:row.currency,amount:row.amount,validUntil:row.valid_until,status:row.status,acceptedAt:row.accepted_at,createdAt:row.created_at,updatedAt:row.updated_at});
