async function workflowBooking(user,id){return db.prepare(`SELECT b.*,g.user_id guide_user_id,g.display_name guide_name,u.name traveler_name FROM bookings b JOIN guide_profiles g ON g.id=b.guide_id JOIN users u ON u.id=b.traveler_id WHERE b.id=? AND (?='admin' OR b.traveler_id=? OR g.user_id=?)`).get(id,user.role,user.id,user.id);}
async function lifecycleEvent(bookingId,userId,type,fromStatus,toStatus,note='',metadata={}){await db.prepare('INSERT INTO booking_lifecycle_events(booking_id,actor_user_id,event_type,from_status,to_status,note,metadata_json) VALUES(?,?,?,?,?,?,?)').run(bookingId,userId,type,fromStatus,toStatus,cleanText(note,1000),JSON.stringify(metadata));}
async function releaseBookingCapacity(booking){for(const date of requestedDates(booking.start_date,booking.end_date))await db.prepare("UPDATE availability_slots SET booked_count=max(0,booked_count-?),updated_at=datetime('now') WHERE guide_id=? AND date=? AND label=?").run(booking.travelers,booking.guide_id,date,booking.slot_label||'Full day');}
route('GET', /^\/api\/bookings\/(\d+)\/workflow$/, async (req,res,_url,match) => { const user=await requireUser(req,res,['traveler','guide','admin']);if(!user)return;const booking=await workflowBooking(user,Number(match[1]));if(!booking)return fail(res,404,'Booking not found');const events=await db.prepare('SELECT e.*,u.name actor_name,u.role actor_role FROM booking_lifecycle_events e LEFT JOIN users u ON u.id=e.actor_user_id WHERE e.booking_id=? ORDER BY e.created_at,e.id').all(booking.id).map(event=>({...event,metadata:json(event.metadata_json)}));reply(res,200,{booking:{id:booking.id,reference:booking.reference,status:booking.operational_status,startDate:booking.start_date,endDate:booking.end_date,pendingStartDate:booking.pending_start_date,pendingEndDate:booking.pending_end_date,changeReason:booking.change_reason,changeRequestedBy:booking.change_requested_by,travelerName:booking.traveler_name,guideName:booking.guide_name},events}); });
route('PATCH', /^\/api\/bookings\/(\d+)\/workflow$/, async (req,res,_url,match) => { const user=await requireUser(req,res,['traveler','guide']);if(!user)return;const booking=await workflowBooking(user,Number(match[1]));if(!booking)return fail(res,404,'Booking not found');const data=await body(req),action=String(data.action||''),current=booking.operational_status||'confirmed',isGuide=user.id===booking.guide_user_id,otherUserId=isGuide?booking.traveler_id:booking.guide_user_id,reason=cleanText(data.reason,1000);if(['request_reschedule','request_cancel'].includes(action)){if(current!=='confirmed')return fail(res,409,'Only confirmed bookings can be changed');if(reason.length<5)return fail(res,400,'Please provide a reason');if(action==='request_reschedule'){const start=String(data.startDate||''),end=String(data.endDate||'');if(!/^\d{4}-\d{2}-\d{2}$/.test(start)||!/^\d{4}-\d{2}-\d{2}$/.test(end)||start>end||requestedDates(start,end).length>31)return fail(res,400,'Valid proposed dates are required');await db.prepare("UPDATE bookings SET operational_status='reschedule_requested',pending_start_date=?,pending_end_date=?,change_requested_by=?,change_reason=?,updated_at=datetime('now') WHERE id=?").run(start,end,user.id,reason,booking.id);await lifecycleEvent(booking.id,user.id,'reschedule_requested',current,'reschedule_requested',reason,{startDate:start,endDate:end});await notify(otherUserId,'booking_change','Reschedule requested',`${user.name} proposed ${start} to ${end} for ${booking.reference}.`,'/traveler-panel.html#bookings');return reply(res,200,{status:'reschedule_requested'});}await db.prepare("UPDATE bookings SET operational_status='cancellation_requested',change_requested_by=?,change_reason=?,updated_at=datetime('now') WHERE id=?").run(user.id,reason,booking.id);await lifecycleEvent(booking.id,user.id,'cancellation_requested',current,'cancellation_requested',reason);await notify(otherUserId,'booking_change','Cancellation requested',`${user.name} requested cancellation of ${booking.reference}.`,'/traveler-panel.html#bookings');return reply(res,200,{status:'cancellation_requested'});}
  if(['approve_change','decline_change'].includes(action)){if(!['reschedule_requested','cancellation_requested'].includes(current))return fail(res,409,'There is no pending change request');if(user.id===booking.change_requested_by)return fail(res,403,'The other booking party must decide this request');if(action==='decline_change'){await db.prepare("UPDATE bookings SET operational_status='confirmed',pending_start_date=NULL,pending_end_date=NULL,change_requested_by=NULL,change_reason=NULL,updated_at=datetime('now') WHERE id=?").run(booking.id);await lifecycleEvent(booking.id,user.id,'change_declined',current,'confirmed',reason||'Change request declined');await notify(booking.change_requested_by,'booking_change','Change request declined',`${user.name} declined the change to ${booking.reference}.`,'/traveler-panel.html#bookings');return reply(res,200,{status:'confirmed'});}if(current==='cancellation_requested'){await db.exec('BEGIN');try{await releaseBookingCapacity(booking);await db.prepare("UPDATE bookings SET status='cancelled',operational_status='cancelled',pending_start_date=NULL,pending_end_date=NULL,change_requested_by=NULL,updated_at=datetime('now') WHERE id=?").run(booking.id);await lifecycleEvent(booking.id,user.id,'cancellation_approved',current,'cancelled',reason||booking.change_reason);await db.exec('COMMIT');}catch(error){await db.exec('ROLLBACK');throw error;}await notify(booking.change_requested_by,'booking_cancelled','Booking cancelled',`${booking.reference} was cancelled.`,'/traveler-panel.html#bookings');return reply(res,200,{status:'cancelled'});}const newDates=requestedDates(booking.pending_start_date,booking.pending_end_date),oldDates=new Set(requestedDates(booking.start_date,booking.end_date)),slots=await db.prepare("SELECT date,capacity-booked_count remaining FROM availability_slots WHERE guide_id=? AND label=? AND status='open' AND date BETWEEN ? AND ?").all(booking.guide_id,booking.slot_label||'Full day',booking.pending_start_date,booking.pending_end_date);if(newDates.some(date=>{const slot=slots.find(item=>item.date===date);return !slot||slot.remaining+(oldDates.has(date)?booking.travelers:0)<booking.travelers;}))return fail(res,409,'The proposed dates no longer have enough capacity');await db.exec('BEGIN');try{await releaseBookingCapacity(booking);for(const date of newDates)await db.prepare("UPDATE availability_slots SET booked_count=booked_count+?,updated_at=datetime('now') WHERE guide_id=? AND date=? AND label=?").run(booking.travelers,booking.guide_id,date,booking.slot_label||'Full day');const oldStart=booking.start_date,oldEnd=booking.end_date;await db.prepare("UPDATE bookings SET start_date=pending_start_date,end_date=pending_end_date,operational_status='confirmed',pending_start_date=NULL,pending_end_date=NULL,change_requested_by=NULL,change_reason=NULL,updated_at=datetime('now') WHERE id=?").run(booking.id);await lifecycleEvent(booking.id,user.id,'reschedule_approved',current,'confirmed',reason||booking.change_reason,{oldStartDate:oldStart,oldEndDate:oldEnd,newStartDate:booking.pending_start_date,newEndDate:booking.pending_end_date});await db.exec('COMMIT');}catch(error){await db.exec('ROLLBACK');throw error;}await notify(booking.change_requested_by,'booking_rescheduled','Booking rescheduled',`${booking.reference} was moved to ${booking.pending_start_date} to ${booking.pending_end_date}.`,'/traveler-panel.html#bookings');return reply(res,200,{status:'confirmed',startDate:booking.pending_start_date,endDate:booking.pending_end_date});}
  if(['complete','no_show'].includes(action)){if(!isGuide)return fail(res,403,'Only the guide can close a trip');if(current!=='confirmed')return fail(res,409,'Only confirmed bookings can be closed');const next=action==='complete'?'completed':'no_show';await db.prepare("UPDATE bookings SET status=?,operational_status=?,updated_at=datetime('now') WHERE id=?").run(action==='complete'?'completed':'cancelled',next,booking.id);await lifecycleEvent(booking.id,user.id,next,current,next,reason);await notify(booking.traveler_id,'booking_closed',action==='complete'?'Trip completed':'No-show recorded',`${booking.reference} is marked ${next.replace('_',' ')}.`,'/traveler-panel.html#bookings');return reply(res,200,{status:next});}return fail(res,400,'Unsupported workflow action'); });
route('PUT', /^\/api\/guide\/availability$/, async (req,res) => { const user=await requireUser(req,res,['guide']);if(!user)return;const guide=await db.prepare('SELECT id FROM guide_profiles WHERE user_id=?').get(user.id);if(!guide)return fail(res,404,'Guide profile not found');const data=await body(req),dates=Array.isArray(data.dates)?data.dates.slice(0,370):[];await db.exec('BEGIN');try{const upsert=await db.prepare(`INSERT INTO availability(guide_id,date,status) VALUES(?,?,?) ON CONFLICT(guide_id,date) DO UPDATE SET status=CASE WHEN availability.status='booked' THEN 'booked' ELSE excluded.status END`);for(const item of dates){if(/^\d{4}-\d{2}-\d{2}$/.test(item.date)&&['available','blocked'].includes(item.status))await upsert.run(guide.id,item.date,item.status);}await db.exec('COMMIT');reply(res,200,{updated:dates.length});}catch(e){await db.exec('ROLLBACK');throw e;} });

async function chatAccess(user,kind,id){
  if(kind==='request')return db.prepare(`SELECT r.id,r.reference,r.traveler_id,r.guide_id,r.start_date,r.end_date,r.focus,r.status,u.name traveler_name,g.display_name guide_name,g.user_id guide_user_id FROM booking_requests r JOIN users u ON u.id=r.traveler_id JOIN guide_profiles g ON g.id=r.guide_id WHERE r.id=? AND (r.traveler_id=? OR g.user_id=?)`).get(id,user.id,user.id);
  if(kind==='booking')return db.prepare(`SELECT b.id,b.reference,b.traveler_id,b.guide_id,b.start_date,b.end_date,b.focus,b.status,u.name traveler_name,g.display_name guide_name,g.user_id guide_user_id FROM bookings b JOIN users u ON u.id=b.traveler_id JOIN guide_profiles g ON g.id=b.guide_id WHERE b.id=? AND (b.traveler_id=? OR g.user_id=?)`).get(id,user.id,user.id);
  return null;
}
route('GET', /^\/api\/chat\/threads$/, async (req,res) => { const user=await requireUser(req,res,['traveler','guide']);if(!user)return;const guide=user.role==='guide'?await db.prepare('SELECT id FROM guide_profiles WHERE user_id=?').get(user.id):null,params=user.role==='traveler'?[user.id]:[guide?.id||-1],owner=user.role==='traveler'?'r.traveler_id=?':'r.guide_id=?',bookingOwner=user.role==='traveler'?'b.traveler_id=?':'b.guide_id=?';const requests=await db.prepare(`SELECT 'request' kind,r.id,r.reference,r.start_date,r.end_date,r.focus,r.status,u.name traveler_name,g.display_name guide_name,(SELECT body FROM booking_messages m WHERE m.booking_request_id=r.id ORDER BY m.id DESC LIMIT 1) last_message,(SELECT created_at FROM booking_messages m WHERE m.booking_request_id=r.id ORDER BY m.id DESC LIMIT 1) last_message_at,(SELECT count(*) FROM booking_messages m WHERE m.booking_request_id=r.id AND m.sender_user_id<>? AND m.read_at IS NULL) unread_count FROM booking_requests r JOIN users u ON u.id=r.traveler_id JOIN guide_profiles g ON g.id=r.guide_id WHERE ${owner} AND r.booking_id IS NULL ORDER BY coalesce(last_message_at,r.created_at) DESC`).all(user.id,...params);const bookings=await db.prepare(`SELECT 'booking' kind,b.id,b.reference,b.start_date,b.end_date,b.focus,b.status,u.name traveler_name,g.display_name guide_name,(SELECT body FROM booking_messages m WHERE m.booking_id=b.id ORDER BY m.id DESC LIMIT 1) last_message,(SELECT created_at FROM booking_messages m WHERE m.booking_id=b.id ORDER BY m.id DESC LIMIT 1) last_message_at,(SELECT count(*) FROM booking_messages m WHERE m.booking_id=b.id AND m.sender_user_id<>? AND m.read_at IS NULL) unread_count FROM bookings b JOIN users u ON u.id=b.traveler_id JOIN guide_profiles g ON g.id=b.guide_id WHERE ${bookingOwner} ORDER BY coalesce(last_message_at,b.created_at) DESC`).all(user.id,...params);reply(res,200,{threads:[...requests,...bookings].sort((a,b)=>String(b.last_message_at||'').localeCompare(String(a.last_message_at||'')))}); });
route('GET', /^\/api\/chat\/threads\/(request|booking)\/(\d+)\/messages$/, async (req,res,_url,match) => { const user=await requireUser(req,res,['traveler','guide']);if(!user)return;const kind=match[1],id=Number(match[2]),thread=await chatAccess(user,kind,id);if(!thread)return fail(res,404,'Conversation not found');const column=kind==='request'?'booking_request_id':'booking_id';await db.prepare(`UPDATE booking_messages SET read_at=datetime('now') WHERE ${column}=? AND sender_user_id<>? AND read_at IS NULL`).run(id,user.id);const messages=await db.prepare(`SELECT m.id,m.body,m.message_type,m.read_at,m.created_at,m.sender_user_id,u.name sender_name,u.role sender_role FROM booking_messages m JOIN users u ON u.id=m.sender_user_id WHERE m.${column}=? ORDER BY m.id`).all(id);reply(res,200,{thread,messages}); });
route('POST', /^\/api\/chat\/threads\/(request|booking)\/(\d+)\/messages$/, async (req,res,_url,match) => { const user=await requireUser(req,res,['traveler','guide']);if(!user)return;const kind=match[1],id=Number(match[2]),thread=await chatAccess(user,kind,id);if(!thread)return fail(res,404,'Conversation not found');const data=await body(req),message=cleanText(data.message,2000);if(message.length<1)return fail(res,400,'Write a message before sending');const column=kind==='request'?'booking_request_id':'booking_id',result=await db.prepare(`INSERT INTO booking_messages(${column},sender_user_id,body) VALUES(?,?,?)`).run(id,user.id,message),recipient=user.id===thread.traveler_id?thread.guide_user_id:thread.traveler_id;if(recipient)await notify(recipient,'chat_message',`New message about ${thread.reference}`,`${user.name}: ${message}`,(user.role==='traveler'?'/guide-admin.html#enquiries':'/traveler-panel.html#bookings'));reply(res,201,{message:{id:Number(result.lastInsertRowid),body:message,senderUserId:user.id,senderName:user.name,createdAt:new Date().toISOString()}}); });
route('GET', /^\/api\/notifications$/, async (req,res) => { const user=await requireUser(req,res);if(!user)return;const items=await db.prepare('SELECT * FROM notifications WHERE user_id=? ORDER BY created_at DESC LIMIT 50').all(user.id),unread=await db.prepare('SELECT count(*) count FROM notifications WHERE user_id=? AND read_at IS NULL').get(user.id).count;reply(res,200,{notifications:items,unread}); });
route('PATCH', /^\/api\/notifications\/read$/, async (req,res) => { const user=await requireUser(req,res);if(!user)return;await db.prepare("UPDATE notifications SET read_at=datetime('now') WHERE user_id=? AND read_at IS NULL").run(user.id);reply(res,200,{ok:true}); });

function money(amount,currency='INR'){return `${currency} ${Number(amount||0).toLocaleString('en-IN')}`;}
async function bookingPdf(row){
  const doc=new PDFDocument({size:'A4',margin:48,bufferPages:true,info:{Title:`Chirps & Roar booking ${row.reference}`,Author:'Chirps & Roar'}}),chunks=[];doc.on('data',chunk=>chunks.push(chunk));const done=new Promise((resolve,reject)=>{doc.on('end',()=>resolve(Buffer.concat(chunks)));doc.on('error',reject);});
  const green='#12392f',lime='#dff29b',muted='#63766e',line='#dce4df';
  const section=title=>{if(doc.y>720)doc.addPage();doc.moveDown(.6).font('Helvetica-Bold').fontSize(10).fillColor(green).text(title.toUpperCase(),{characterSpacing:1});doc.moveDown(.35).strokeColor(line).moveTo(48,doc.y).lineTo(547,doc.y).stroke();doc.moveDown(.55);};
  const field=(label,value,x,y,width=230)=>{doc.font('Helvetica').fontSize(8).fillColor(muted).text(label.toUpperCase(),x,y,{width});doc.font('Helvetica-Bold').fontSize(11).fillColor(green).text(String(value||'-'),x,y+13,{width});};
  doc.rect(0,0,595,118).fill(green);doc.roundedRect(48,35,38,38,7).fill(lime);doc.font('Helvetica-Bold').fontSize(13).fillColor(green).text('C&R',53,47);doc.font('Helvetica-Bold').fontSize(19).fillColor('#ffffff').text('CHIRPS & ROAR',100,38);doc.font('Helvetica').fontSize(9).fillColor('#cfe0d9').text('CONFIRMED GUIDE BOOKING',100,66);doc.font('Helvetica-Bold').fontSize(13).fillColor('#ffffff').text(row.reference,410,47,{width:137,align:'right'});
  doc.y=145;doc.font('Helvetica-Bold').fontSize(25).fillColor(green).text(row.quote_title||`${row.focus} guided experience`,48,145,{width:499});doc.moveDown(.35).font('Helvetica').fontSize(10).fillColor(muted).text('Your confirmed itinerary and direct-payment record. Keep this document available during the trip.');
  let y=220;field('Traveler',row.traveler_name,48,y);field('Guide',row.guide_name,310,y);y+=55;field('Trip dates',`${row.start_date} to ${row.end_date}`,48,y);field('Travelers',row.travelers,310,y);y+=55;field('Meeting location',row.meeting_location||row.guide_location,48,y);field('Meeting time',row.meeting_time||'Coordinate with guide',310,y);
  doc.y=y+55;section('Booking and payment');const paymentLabels={not_recorded:'Not recorded - pay guide directly',deposit_paid:'Deposit paid',paid_in_full:'Paid in full',pay_on_arrival:'Payment due on arrival'},paymentY=doc.y;field('Order amount',money(row.total,row.currency||'INR'),48,paymentY);field('Payment status',paymentLabels[row.payment_status]||row.payment_status,310,paymentY);doc.y=paymentY+52;if(row.amount_recorded>0)doc.font('Helvetica').fontSize(9).fillColor(muted).text(`Amount recorded: ${money(row.amount_recorded,row.currency||'INR')}${row.payment_note?`  |  ${row.payment_note}`:''}`);
  const itinerary=json(row.itinerary_json);section('Day-by-day itinerary');if(itinerary.length)for(const item of itinerary){if(doc.y>720)doc.addPage();const itemY=doc.y;doc.roundedRect(48,itemY,36,26,4).fill(lime);doc.font('Helvetica-Bold').fontSize(8).fillColor(green).text(`DAY ${item.day}`,50,itemY+9,{width:32,align:'center',lineBreak:false});doc.font('Helvetica-Bold').fontSize(12).fillColor(green).text(item.title,98,itemY,{width:449});const description=String(item.description||''),descriptionHeight=doc.font('Helvetica').fontSize(9).heightOfString(description,{width:449,lineGap:2});doc.fillColor(muted).text(description,98,itemY+18,{width:449,lineGap:2});doc.y=itemY+Math.max(38,24+descriptionHeight)+8;}else doc.font('Helvetica').fontSize(9).fillColor(muted).text('Coordinate the detailed daily plan directly with your guide.');
  const listSection=(title,items)=>{section(title);if(items.length)doc.font('Helvetica').fontSize(9).fillColor(green).list(items.map(String),{bulletRadius:2,textIndent:14,lineGap:4});else doc.font('Helvetica').fontSize(9).fillColor(muted).text('None specified.');};listSection('Included',json(row.inclusions_json));listSection('Not included',json(row.exclusions_json));if(row.guide_notes){section('Guide notes');doc.font('Helvetica').fontSize(9).fillColor(green).text(row.guide_notes,{lineGap:3});}
  section('Important');doc.font('Helvetica').fontSize(8.5).fillColor(muted).text('Payment is arranged directly between the traveler and guide. Chirps & Roar records the status provided by the parties but does not process or guarantee the payment. Contact your guide through the booking conversation if trip details change.',{lineGap:3});
  const pages=doc.bufferedPageRange();for(let i=0;i<pages.count;i++){doc.switchToPage(i);doc.font('Helvetica').fontSize(8).fillColor(muted).text(`Chirps & Roar  |  ${row.reference}  |  Page ${i+1} of ${pages.count}`,48,780,{width:499,align:'center'});}doc.end();return done;
}
route('GET', /^\/api\/bookings\/(\d+)\/document\.pdf$/, async (req,res,_url,match) => { const user=await requireUser(req,res,['traveler','guide','admin']);if(!user)return;const row=await db.prepare(`SELECT b.*,u.name traveler_name,u.email traveler_email,g.display_name guide_name,g.primary_location guide_location,g.user_id guide_user_id,d.status payment_status,d.amount_recorded,d.note payment_note,q.title quote_title,q.meeting_location,q.meeting_time,q.itinerary_json,q.inclusions_json,q.exclusions_json,q.guide_notes,q.currency FROM bookings b JOIN users u ON u.id=b.traveler_id JOIN guide_profiles g ON g.id=b.guide_id LEFT JOIN direct_payment_records d ON d.booking_id=b.id LEFT JOIN booking_requests r ON r.booking_id=b.id LEFT JOIN booking_quotes q ON q.booking_request_id=r.id WHERE b.id=?`).get(Number(match[1]));if(!row||(user.role!=='admin'&&user.id!==row.traveler_id&&user.id!==row.guide_user_id))return fail(res,404,'Confirmed booking not found');const pdf=await bookingPdf(row);res.writeHead(200,{'Content-Type':'application/pdf','Content-Disposition':`attachment; filename="chirps-and-roar-${row.reference}.pdf"`,'Content-Length':pdf.length,'Cache-Control':'private, no-store'});res.end(pdf); });

route('POST', /^\/api\/payments\/session$/, async (req,res) => { if(!await requireUser(req,res,['traveler']))return; fail(res,410,'Online checkout is not enabled. Payment is arranged directly with the guide.'); });
route('POST', /^\/api\/payments\/mock-confirm$/, async (req,res) => { if(!await requireUser(req,res,['traveler']))return; fail(res,410,'Online checkout is not enabled. Payment is arranged directly with the guide.'); });

route('POST', /^\/api\/reviews$/, async (req,res) => { const traveler=await requireUser(req,res,['traveler']);if(!traveler)return;const data=await body(req),booking=await db.prepare("SELECT * FROM bookings WHERE (id=? OR reference=?) AND traveler_id=? AND status='completed'").get(Number(data.bookingId)||-1,String(data.bookingId||''),traveler.id);if(!booking)return fail(res,403,'Only completed bookings can be reviewed');const ratings=['overall','knowledge','communication','organisation','value'];if(ratings.some(k=>Number(data[k])<1||Number(data[k])>5)||cleanText(data.title,80).length<3||cleanText(data.body,1200).length<30)return fail(res,400,'Complete all ratings, title and review text');try{const result=await db.prepare(`INSERT INTO reviews(booking_id,traveler_id,guide_id,overall,knowledge,communication,organisation,value,title,body,photos_json) VALUES(?,?,?,?,?,?,?,?,?,?,?)`).run(booking.id,traveler.id,booking.guide_id,...ratings.map(k=>Number(data[k])),cleanText(data.title,80),cleanText(data.body,1200),JSON.stringify(data.photos||[]));const stats=await db.prepare("SELECT avg(overall) rating,count(*) count FROM reviews WHERE guide_id=? AND status='published'").get(booking.guide_id);await db.prepare('UPDATE guide_profiles SET rating=?,review_count=? WHERE id=?').run(Number(Number(stats.rating).toFixed(1)),stats.count,booking.guide_id);reply(res,201,{id:Number(result.lastInsertRowid),verified:true});}catch(e){if(String(e.message).includes('UNIQUE'))return fail(res,409,'This booking has already been reviewed');throw e;} });

export async function handleApiRequest(req,res,url) {
  try {
    const found=routes.find(r=>r.method===req.method&&r.pattern.test(url.pathname));
    if(!found)return fail(res,404,'API endpoint not found');
    const match=url.pathname.match(found.pattern);
    return await found.handler(req,res,url,match);
  } catch(error) { console.error(error); if(!res.headersSent)fail(res,error.status||500,error.status?error.message:'Internal server error');else res.end(); }
}
